1	#pragma once
2	
3	#include <cutlass/half.h>
4	#include <cutlass/fast_math.h>
5	
6	#include "common.h"
7	#include "params.h"
8	
9	#include "sm90/decode/dense/splitkv_mla.h"
10	#include "smxx/decode/get_decoding_sched_meta/get_decoding_sched_meta.h"
11	#include "smxx/decode/combine/combine.h"
12	
13	static std::tuple<at::Tensor, at::Tensor, std::optional<at::Tensor>, std::optional<at::Tensor>>
14	dense_attn_decode_interface(
15	    at::Tensor &q,                               // batch_size x seqlen_q x num_heads x head_size
16	    const at::Tensor &kcache,                    // num_blocks x page_block_size x num_heads_k x head_size (when is_fp8 is False) or num_blocks x num_heads_k x (page_block_size*656) (when is_fp8 is True)
17	    const int head_size_v,
18	    const at::Tensor &seqlens_k,                 // batch_size
19	    const at::Tensor &block_table,               // batch_size x max_num_blocks_per_seq
20	    const float softmax_scale,
21	    bool is_causal,
22	    std::optional<at::Tensor> &tile_scheduler_metadata,   // num_sm_parts x (DecodingSchedMetaSize/4)
23	    std::optional<at::Tensor> &num_splits                 // batch_size + 1
24	) {
25	    // Check arch
26	    Arch arch = Arch();
27	    if (!arch.is_sm90a()) {
28	        TORCH_CHECK(false, "Dense decode MLA is only supported on SM90a architecture");
29	    }
30	
31	    // Check data types
32	    auto q_dtype = q.dtype();
33	    TORCH_CHECK(q_dtype == torch::kBFloat16 || q_dtype == torch::kHalf);
34	    
35	    TORCH_CHECK(kcache.dtype() == q_dtype, "query and key must have the same dtype");
36	    TORCH_CHECK(seqlens_k.dtype() == torch::kInt32, "seqlens_k must have dtype int32");
37	    TORCH_CHECK(block_table.dtype() == torch::kInt32, "block_table must have dtype torch.int32");
38	
39	    // Check device
40	    KU_CHECK_DEVICE(q);
41	    KU_CHECK_DEVICE(kcache);
42	    KU_CHECK_DEVICE(seqlens_k);
43	    KU_CHECK_DEVICE(block_table);
44	    KU_CHECK_DEVICE(tile_scheduler_metadata);
45	    KU_CHECK_DEVICE(num_splits);
46	
47	    // Check layout
48	    TORCH_CHECK(q.stride(-1) == 1, "q must have contiguous last dimension");
49	    TORCH_CHECK(kcache.stride(-1) == 1, "kcache must have contiguous last dimension");
50	    KU_CHECK_CONTIGUOUS(seqlens_k);
51	    TORCH_CHECK(block_table.stride(-1) == 1, "block_table must have contiguous last dimension");
52	    KU_CHECK_CONTIGUOUS(tile_scheduler_metadata);
53	    KU_CHECK_CONTIGUOUS(num_splits);
54	
55	    const auto sizes = q.sizes();
56	    const int batch_size = sizes[0];
57	    const int seqlen_q_ori = sizes[1];
58	    const int num_heads_q = sizes[2];
59	    const int head_size_k = sizes[3];
60	    TORCH_CHECK(head_size_k == 576 || head_size_k == 512, "Only head_size_k == 576 or 512 is supported");
61	    TORCH_CHECK(head_size_v == 512, "Only head_size_v == 576 is supported");
62	    
63	    const int max_num_blocks_per_seq = block_table.size(1);
64	    const int num_blocks = kcache.size(0);
65	    const int page_block_size = kcache.size(1);
66	    const int num_heads_k = kcache.size(2);
67	    TORCH_CHECK(page_block_size == 64, "Currently page_block_size must be 64");
68	    TORCH_CHECK(batch_size > 0, "batch size must be positive");
69	    TORCH_CHECK(num_heads_q % num_heads_k == 0, "Number of heads in key/value must divide number of heads in query");
70	    
71	    if (seqlen_q_ori == 1) { is_causal = false; }
72	    
73	    const int num_q_heads_per_hk = num_heads_q / num_heads_k;
74	    const int q_seq_per_hk = seqlen_q_ori * num_q_heads_per_hk;
75	    const int num_heads = num_heads_k;
76	    q = q.view({batch_size, seqlen_q_ori, num_heads_k, num_q_heads_per_hk, head_size_k}).transpose(2, 3)
77	        .reshape({batch_size, q_seq_per_hk, num_heads, head_size_k});
78	    int num_sm_parts = std::max(arch.num_sms / num_heads_k / cutlass::ceil_div(seqlen_q_ori*num_heads_q/num_heads_k, 64), 1);
79	
80	    KU_CHECK_SHAPE(q, batch_size, q_seq_per_hk, num_heads, head_size_k);
81	    KU_CHECK_SHAPE(kcache, num_blocks, page_block_size, num_heads_k, head_size_k);
82	    KU_CHECK_SHAPE(seqlens_k, batch_size);
83	    KU_CHECK_SHAPE(block_table, batch_size, max_num_blocks_per_seq);
84	    KU_CHECK_SHAPE(tile_scheduler_metadata, num_sm_parts, DecodingSchedMetaSize/sizeof(int));
85	    KU_CHECK_SHAPE(num_splits, batch_size+1);
86	
87	    at::cuda::CUDAGuard device_guard{(char)q.get_device()};
88	
89	    auto opts = q.options();
90	    at::Tensor out = torch::empty({batch_size, num_heads, q_seq_per_hk, head_size_v}, opts);
91	    at::Tensor lse = torch::empty({batch_size, num_heads, q_seq_per_hk}, opts.dtype(at::kFloat));
92	    KU_CHECK_CONTIGUOUS(out);
93	    KU_CHECK_CONTIGUOUS(lse);
94	
95	    if (!tile_scheduler_metadata.has_value()) {
96	        tile_scheduler_metadata = torch::empty({num_sm_parts, sizeof(DecodingSchedMeta)/4}, opts.dtype(torch::kInt32));
97	        num_splits = torch::empty({batch_size+1}, opts.dtype(torch::kInt32));
98	        KU_CHECK_CONTIGUOUS(tile_scheduler_metadata);
99	        KU_CHECK_CONTIGUOUS(num_splits);
100	    
101	        GetDecodeSchedMetaParams get_sched_meta_params = {
102	            batch_size, seqlen_q_ori,
103	            64,
104	            5,
105	            -1, -1,
106	            nullptr, nullptr,
107	            seqlens_k.data_ptr<int>(),
108	            (DecodingSchedMeta*)tile_scheduler_metadata->data_ptr(),
109	            num_splits->data_ptr<int>(),
110	            num_sm_parts,
111	            at::cuda::getCurrentCUDAStream().stream()
112	        };
113	        smxx::decode::run_get_decoding_sched_meta_kernel(get_sched_meta_params);
114	    } else {
115	        KU_CHECK_DTYPE(tile_scheduler_metadata, torch::kInt32);
116	        KU_CHECK_DTYPE(num_splits, torch::kInt32);
117	        KU_CHECK_DEVICE(tile_scheduler_metadata);
118	        KU_CHECK_DEVICE(num_splits);
119	        KU_CHECK_CONTIGUOUS(tile_scheduler_metadata);
120	        KU_CHECK_CONTIGUOUS(num_splits);
121	        KU_CHECK_SHAPE(tile_scheduler_metadata, num_sm_parts, sizeof(DecodingSchedMeta)/sizeof(int));
122	        KU_CHECK_SHAPE(num_splits, batch_size+1);
123	    }
124	
125	    // Set the sizes
126	    DenseAttnDecodeParams params;
127	    params.b = batch_size;
128	    params.s_q = seqlen_q_ori;
129	    params.q_seq_per_hk = q_seq_per_hk;
130	    params.seqlens_k_ptr = seqlens_k.data_ptr<int>();
131	    params.h_q = num_heads_q;
132	    params.h_k = num_heads_k;
133	    params.num_blocks = num_blocks;
